// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define INF INT_MAX
#define MIN(a, b) ((a) < (b) ? (a) : (b))
typedef struct {
    int town;
    int cost;
} Edge;
typedef struct {
    int town;
    int up;
    int down;
} Town;

int compare(const void *a, const void *b) {
    Edge *e1 = (Edge *)a;
    Edge *e2 = (Edge *)b;
    return e1->cost - e2->cost;
}

int main() {
    int N, R;
    scanf("%d %d", &N, &R);
    int *H = (int *)malloc(N * sizeof(int));
    int *C = (int *)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &H[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%d", &C[i]);
    }
    Edge *edges = (Edge *)malloc(R * sizeof(Edge));
    for (int i = 0; i < R; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        u--;
        v--;
        edges[i].town = v;
        edges[i].cost = C[u];
    }
    qsort(edges, R, sizeof(Edge), compare);
    Town *towns = (Town *)malloc(N * sizeof(Town));
    for (int i = 0; i < N; i++) {
        towns[i].town = i;
        towns[i].up = INF;
        towns[i].down = INF;
    }
    towns[0].up = 0;
    for (int i = 0; i < R; i++) {
        int u = edges[i].town;
        int cost = edges[i].cost;
        if (H[u] >= H[towns[0].town]) {
            towns[u].down = MIN(towns[u].down, towns[0].up + cost);
        } else {
            towns[u].up = MIN(towns[u].up, towns[0].up + cost);
        }
    }
    int minCost = INF;
    for (int i = 0; i < N; i++) {
        minCost = MIN(minCost, towns[i].up + towns[i].down);
    }
    if (minCost == INF) {
        printf("-1\n");
    } else {
        printf("%d\n", minCost);
    }
    free(H);
    free(C);
    free(edges);
    free(towns);
    return 0;
}

