#include <iostream>
#include <queue>
#include <vector>
#include <limits>
using namespace std;
#define INF numeric_limits<int>::max()
#define MIN(a, b) ((a) < (b) ? (a) : (b))
typedef pair<int, int> Edge;
typedef pair<int, pair<int, int>> Town;

int main() {
    int N, R;
    cin >> N >> R;
    vector<int> H(N), C(N);
    for (int i = 0; i < N; i++) {
        cin >> H[i];
    }
    for (int i = 0; i < N; i++) {
        cin >> C[i];
    }
    vector<Edge> edges(R);
    for (int i = 0; i < R; i++) {
        int u, v;
        cin >> u >> v;
        u--;
        v--;
        edges[i] = make_pair(v, C[u]);
    }
    priority_queue<Edge, vector<Edge>, greater<Edge>> pq;
    vector<Town> towns(N);
    for (int i = 0; i < N; i++) {
        towns[i] = make_pair(i, make_pair(INF, INF));
    }
    towns[0].second.first = 0;
    pq.push(make_pair(0, 0));
    while (!pq.empty()) {
        int u = pq.top().second;
        int cost = pq.top().first;
        pq.pop();
        for (int i = 0; i < R; i++) {
            int v = edges[i].first;
            int newCost = edges[i].second;
            if (H[v] >= H[u]) {
                if (towns[v].second.second > cost + newCost) {
                    towns[v].second.second = cost + newCost;
                    pq.push(make_pair(towns[v].second.second, v));
                }
            } else {
                if (towns[v].second.first > cost + newCost) {
                    towns[v].second.first = cost + newCost;
                    pq.push(make_pair(towns[v].second.first, v));
                }
            }
        }
    }
    int minCost = INF;
    for (int i = 0; i < N; i++) {
        minCost = MIN(minCost, towns[i].second.first + towns[i].second.second);
    }
    if (minCost == INF) {
        cout << -1 << endl;
    } else {
        cout << minCost << endl;
    }
    return 0;
}

