// COMPLETE, COMPILABLE Java code
import java.util.PriorityQueue;
import java.util.Scanner;
import java.util.Vector;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int R = sc.nextInt();
        int[] H = new int[N];
        int[] C = new int[N];
        for (int i = 0; i < N; i++) {
            H[i] = sc.nextInt();
        }
        for (int i = 0; i < N; i++) {
            C[i] = sc.nextInt();
        }
        Vector<int[]> edges = new Vector<>();
        for (int i = 0; i < R; i++) {
            int u = sc.nextInt() - 1;
            int v = sc.nextInt() - 1;
            edges.add(new int[] {v, C[u]});
        }
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[0] - b[0]);
        int[][] towns = new int[N][3];
        for (int i = 0; i < N; i++) {
            towns[i][0] = i;
            towns[i][1] = Integer.MAX_VALUE;
            towns[i][2] = Integer.MAX_VALUE;
        }
        towns[0][1] = 0;
        pq.add(new int[] {0, 0});
        while (!pq.isEmpty()) {
            int[] curr = pq.poll();
            int u = curr[1];
            int cost = curr[0];
            for (int i = 0; i < R; i++) {
                int v = edges.get(i)[0];
                int newCost = edges.get(i)[1];
                if (H[v] >= H[u]) {
                    if (towns[v][2] > cost + newCost) {
                        towns[v][2] = cost + newCost;
                        pq.add(new int[] {towns[v][2], v});
                    }
                } else {
                    if (towns[v][1] > cost + newCost) {
                        towns[v][1] = cost + newCost;
                        pq.add(new int[] {towns[v][1], v});
                    }
                }
            }
        }
        int minCost = Integer.MAX_VALUE;
        for (int i = 0; i < N; i++) {
            minCost = Math.min(minCost, towns[i][1] + towns[i][2]);
        }
        if (minCost == Integer.MAX_VALUE) {
            System.out.println(-1);
        } else {
            System.out.println(minCost);
        }
    }
}

